import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is prime factorization?", a: "Prime factorization writes a number as a product of prime numbers. For example, 60 = 2^2 x 3 x 5." },
  { q: "How do you find the prime factorization of a number?", a: "Divide the number by the smallest possible prime repeatedly, then continue with the next primes until the quotient becomes 1." },
  { q: "What is a prime number?", a: "A prime number is a whole number greater than 1 with exactly two positive factors: 1 and itself." },
  { q: "How is prime factorization used to find LCM and GCF?", a: "For GCF, use shared prime factors at their lowest powers. For LCM, use every prime factor at its highest power." },
  { q: "What is a factor tree?", a: "A factor tree is a visual way to split a number into factors until all branches end in prime numbers." },
];

const factorize = (n: number) => {
  const factors: number[] = [];
  const steps: string[] = [];
  let x = Math.abs(Math.trunc(n));
  for (let p = 2; p * p <= x; p++) {
    while (x % p === 0) {
      steps.push(`${x}  x  ${p} = ${x / p}`);
      factors.push(p);
      x /= p;
    }
  }
  if (x > 1) { factors.push(x); steps.push(`${x} is prime`); }
  return { factors, steps };
};

export default function PrimeFactorizationCalculator() {
  const [value, setValue] = useState(360);
  const result = useMemo(() => {
    const n = Math.abs(Math.trunc(value));
    if (n < 2) return null;
    const { factors, steps } = factorize(n);
    const counts = new Map<number, number>();
    factors.forEach((f) => counts.set(f, (counts.get(f) || 0) + 1));
    const expanded = factors.join(" x ");
    const exponential = [...counts.entries()].map(([p, e]) => e === 1 ? `${p}` : `${p}^${e}`).join(" x ");
    return { n, factors, expanded, exponential, steps };
  }, [value]);

  return (
    <>
      <SEOHead title="Free Prime Factorization Calculator Online - Find Prime Factors of Any Number Instantly | CalcHive" description="Free online prime factorization calculator. Find the prime factorization of any number with step by step solution in exponential and expanded form. 100% free for students, no signup required." canonical="/prime-factorization-calculator" keywords="free prime factorization calculator, prime factors calculator free online, find prime factorization free, factor tree calculator free, prime decomposition calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Prime Factorization Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free prime factorization calculator to find prime factorization free in expanded and exponential form.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="prime-factor-value" className="text-sm font-semibold text-foreground block mb-2">Positive integer</label>
          <input id="prime-factor-value" type="number" min="2" value={value} onChange={(e) => setValue(Number(e.target.value))} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          {result ? <motion.div key={value} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Prime Factorization</p><p className="text-4xl font-black text-white tracking-tight" data-testid="result-prime-factorization">{result.exponential}</p><p className="text-white/70 text-sm mt-1">Expanded: {result.expanded}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.steps.join("; ")}. Prime factors: {result.factors.join(", ")}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-6">Enter a whole number greater than 1.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Find the Prime Factorization of Any Number for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a positive integer and this prime factors calculator free online divides it into prime factors step by step.</p><h2 className="text-2xl font-bold text-foreground">What is Prime Factorization and How Does It Work</h2><p className="text-muted-foreground leading-relaxed">Prime factorization decomposes a number into prime numbers that multiply back to the original number.</p><h2 className="text-2xl font-bold text-foreground">Free Prime Factor Tree Calculator for Students</h2><p className="text-muted-foreground leading-relaxed">Use this factor tree calculator free and prime decomposition calculator free for GCF, LCM, and number theory homework.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/prime-factorization-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


